    // Read score count, then use read_container to read the scores vector
    uint32_t score_count = reader.get<uint32_t>();
    std::vector<uint32_t> scores(score_count);
    reader.read_container(scores);

    // Read metadata string as null-terminated for zero-copy
    std::string metadata = reader.get<std::string>(hexi::null_terminated());

    // Skip any remaining padding bytes
    reader.skip(reader.remaining());

    return NetworkPacket{packet_id, std::move(username), std::move(scores), std::move(metadata)};
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    auto reader = hexi::reader{buffer};

    // Use span() to get a zero-copy view of the packet_id (first 4 bytes)
    auto packet_id_span = reader.span<4>();
    uint32_t packet_id;
