struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Use span's subspan to get a zero-copy view of the header data
    auto header_span = buffer.subspan(0, sizeof(PacketHeader));

    // Create a PacketHeader by reading the bytes from the span
    // This assumes the buffer contains properly aligned data for the struct
    return *reinterpret_cast<const PacketHeader*>(header_span.data());
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Find the null terminator in the buffer
    const auto* start = reinterpret_cast<const char*>(buffer.data());
    const auto* end = reinterpret_cast<const char*>(buffer.data() + buffer.size());
    const auto* null_pos = std::find(start, end, '\0');

    // Calculate the length of the string (without null terminator)
    size_t length = (null_pos != end) ? (null_pos - start) : buffer.size();

    // Return a string_view of the message data
    return std::string_view(start, length);
}
```

