    if (adaptor.available() < sizeof(uint8_t)) {
        // Not enough data for even the data_type
        return result;
    }

    uint8_t data_type = adaptor.peek<uint8_t>();
    result.data_type = data_type;

    // Check if we have enough data for the header (data_type + item_count)
