        // Not enough data for complete header
        return result;
    }

    // Now create a binary stream for reading the actual data
    hexi::binary_stream stream(buffer.data(), buffer.size());

    // Read data_type (this will advance the stream pointer)
    data_type = stream.read<uint8_t>();

    // Read item_count
    uint32_t item_count = stream.read<uint32_t>();

    // Calculate required data size for items
    size_t item_size = (data_type == 0) ? sizeof(uint32_t) : sizeof(float);
    size_t required_size = sizeof(uint8_t) + sizeof(uint32_t) + (item_count * item_size);

    // Check if we have enough data for all items
    if (buffer.size() < required_size) {
        // Not enough data for all items
        return result;
    }

    // Read items based on data type
    if (data_type == 0) {
        // Integer data
        result.int_items.reserve(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            result.int_items.push_back(stream.read<uint32_t>());
