template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Check if there's enough data to peek
    if (bytes_to_peek > buffer.size()) {
        throw std::out_of_range("peek_data_from_buffer: bytes_to_peek exceeds available data");
    }

