#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using namespace hexi;

    // Create a block allocator for integers
    block_allocator<int, element_count> allocator;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Allocator capacity: " << element_count << " elements\n\n";

    // Track allocated pointers to observe free list behavior
    std::vector<int*> allocated_ptrs;

    // Phase 1: Allocate all available blocks
    std::cout << "Phase 1: Allocating all " << element_count << " blocks:\n";
    for (size_t i = 0; i < element_count; ++i) {
        int* ptr = allocator.allocate(1);
        *ptr = static_cast<int>(i); // Initialize with value
        allocated_ptrs.push_back(ptr);
        std::cout << "Allocated block " << i << " at address: " << ptr 
                  << " (value: " << *ptr << ")\n";
    }

    std::cout << "\nAll blocks allocated. Free list should be empty now.\n\n";

    // Phase 2: Deallocate blocks in reverse order (simulating LIFO behavior)
    std::cout << "Phase 2: Deallocating blocks in REVERSE order (LIFO):\n";
    for (int i = static_cast<int>(element_count) - 1; i >= 0; --i) {
        std::cout << "Deallocating block " << i << " at address: " 
                  << allocated_ptrs[i] << "\n";
        allocator.deallocate(allocated_ptrs[i], 1);
    }

    std::cout << "\nAll blocks deallocated. Free list should contain all blocks in reverse allocation order.\n\n";

    // Phase 3: Reallocate to observe free list LIFO behavior
    std::cout << "Phase 3: Reallocating blocks (should follow LIFO order):\n";
    for (size_t i = 0; i < element_count; ++i) {
        int* ptr = allocator.allocate(1);
        *ptr = static_cast<int>(i + 100); // Different values to distinguish
        std::cout << "Reallocated block " << i << " at address: " << ptr 
                  << " (value: " << *ptr << ")";

        // Show that we're getting blocks in reverse deallocation order
        // (which is the original allocation order due to LIFO)
        if (ptr == allocated_ptrs[element_count - 1 - i]) {
            std::cout << " <-- Matches original block " << (element_count - 1 - i);
        }
        std::cout << "\n";
        allocator.deallocate(ptr, 1); // Clean up immediately for demonstration
    }

    // Phase 4: Demonstrate mixed allocation pattern
    std::cout << "\nPhase 4: Mixed allocation pattern demonstration:\n";

    // Allocate 3 blocks
    int* block1 = allocator.allocate(1);
    int* block2 = allocator.allocate(1);
    int* block3 = allocator.allocate(1);
    *block1 = 1; *block2 = 2; *block3 = 3;

    std::cout << "Allocated 3 blocks:\n";
    std::cout << "Block 1: " << block1 << " (value: " << *block1 << ")\n";
    std::cout << "Block 2: " << block2 << " (value: " << *block2 << ")\n";
    std::cout << "Block 3: " << block3 << " (value: " << *block3 << ")\n";

    // Deallocate middle block first
    std::cout << "\nDeallocating Block 2 first...\n";
    allocator.deallocate(block2, 1);

    // Deallocate other blocks
    std::cout << "Deallocating Block 1...\n";
    allocator.deallocate(block1, 1);
    std::cout << "Deallocating Block 3...\n";
    allocator.deallocate(block3, 1);

    // Reallocate to see free list order
    std::cout << "\nReallocating 3 blocks (LIFO order expected):\n";
    int* new1 = allocator.allocate(1);
    int* new2 = allocator.allocate(1);
    int* new3 = allocator.allocate(1);

    std::cout << "New Block 1: " << new1;
    if (new1 == block3) std::cout << " (was Block 3)";
    std::cout << "\n";

    std::cout << "New Block 2: " << new2;
    if (new2 == block1) std::cout << " (was Block 1)";
    std::cout << "\n";

    std::cout << "New Block 3: " << new3;
    if (new3 == block2) std::cout << " (was Block 2)";
    std::cout << "\n";

    // Clean up
    allocator.deallocate(new1, 1);
    allocator.deallocate(new2, 1);
    allocator.deallocate(new3, 1);

    std::cout << "\n=== Demonstration Complete ===\n";
    std::cout << "Summary: The free list operates as a LIFO stack.\n";
    std::cout << "- push() adds to the head (most recently freed)\n";
    std::cout << "- pop() removes from the head (most recently freed)\n";
    std::cout << "This provides O(1) allocation/deallocation performance.\n";
}

