```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path.string(), "rb");

    // Get the actual readable size (don't read beyond file size)
    size_t actual_read_size = std::min(bytes_to_read, file.size());

    // Create destination buffer
    std::vector<uint8_t> buffer(actual_read_size);

    // Read data from file into buffer
    if (actual_read_size > 0) {
        file.read(buffer.data(), actual_read_size);
    }

    return buffer;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path.string(), "rb");

    // Get current read position
    size_t current_pos = file.tell();

    // Get the actual preview size (don't read beyond file size)
    size_t actual_preview_size = std::min(bytes_to_preview, file.size() - current_pos);

    // Create destination buffer
    std::vector<uint8_t> buffer(actual_preview_size);

    // Read data without advancing pointer (read and seek back)
    if (actual_preview_size > 0) {
        file.read(buffer.data(), actual_preview_size);
        file.seek(current_pos); // Seek back to original position
    }

    return buffer;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create a file_buffer object for writing
    hexi::file_buffer file(file_path.string(), "wb");

    // Write data to file
    if (!data.empty()) {
        file.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create a file_buffer object for reading
    hexi::file_buffer file(file_path.string(), "rb");

    // Return the size of readable data in the file
    return file.size();
}
```

