#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a file buffer and open the file
    hexi::file_buffer file;
    if (!file.open(file_path.string(), "rb")) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Get the current read position to restore later
    size_t original_pos = file.tell();

    // Seek to the beginning of the file
    file.seek(0, SEEK_SET);

    // Read the header data
    std::vector<uint8_t> header_data(header_size);
    size_t bytes_read = file.read(header_data.data(), header_size);

    // Resize the vector to the actual number of bytes read
    // (in case the file is smaller than header_size)
    header_data.resize(bytes_read);

    // Restore the original read position
    file.seek(original_pos, SEEK_SET);

    return header_data;
}
```

This implementation:

1. Opens the file using Hexi's `file_buffer` class
2. Saves the current read position using `tell()`
3. Seeks to the beginning of the file
4. Reads the requested number of bytes into a vector
5. Resizes the vector to match the actual bytes read (in case the file is smaller than requested)
6. Restores the original read position before returning

The function returns an empty vector if the file cannot be opened, or a vector containing the header bytes (which may be smaller than requested if the file is small).

