    std::vector<uint8_t> result;

    // Read the specified number of bytes or until buffer is empty
    size_t bytes_read = 0;
    while (bytes_read < bytes_to_read && !buffer.empty()) {
        std::byte data_byte;
        if (buffer.read(data_byte)) {
            result.push_back(static_cast<uint8_t>(data_byte));
            bytes_read++;
        }
    }

    return result;
}
