template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, const std::vector<uint8_t>& data) {
    // Clear existing data
    buffer.clear();

    // Write all data to buffer
    for (const auto& byte : data) {
        if (!buffer.write(static_cast<std::byte>(byte))) {
            // Buffer is full, stop writing
            break;
        }
    }
}

template<size_t buffer_size = 1024>
std::vector<uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_read) {
    std::vector<uint8_t> result;

    // Determine how many bytes we can actually read
    size_t available_bytes = buffer.size();
    size_t bytes_to_extract = std::min(bytes_to_read, available_bytes);

    // Reserve space for efficiency
    result.reserve(bytes_to_extract);

    // Read bytes from buffer
    for (size_t i = 0; i < bytes_to_extract; ++i) {
        std::byte data_byte;
        if (buffer.read(data_byte)) {
            result.push_back(static_cast<uint8_t>(data_byte));
        } else {
            // Read failed, break early
            break;
        }
    }

    return result;
}
```

