#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <string>

void write_string_to_stream(hexi::pmc::binary_stream_writer& writer, const std::string& str) {
    // Write the length of the string as a prefix
    writer.write(static_cast<uint32_t>(str.length()));

    // Write the string data
    if (!str.empty()) {
        writer.write(str.data(), str.length());
    }
}

std::string read_string_from_stream(hexi::pmc::binary_stream_reader& reader) {
    // Read the length prefix
    uint32_t length = 0;
    reader.read(length);

    // Handle empty string case
    if (length == 0) {
        return std::string();
    }

    // Read the string data
    std::string result;
    result.resize(length);
    reader.read(&result[0], length);

    return result;
}
```

This implementation follows the typical pattern for prefixed string serialization:

1. **Writing**: 
   - First writes the string length as a 32-bit unsigned integer prefix
   - Then writes the actual string data (if the string is not empty)

2. **Reading**:
   - First reads the length prefix to know how many bytes to read
   - Resizes the result string to accommodate the data
   - Reads the string data into the pre-allocated buffer

The code handles edge cases like empty strings properly and uses the Hexi library's `write` and `read` methods for binary serialization. The 32-bit length prefix ensures compatibility with strings of various sizes while maintaining a consistent format.

