void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Save current write position
    std::size_t current_pos = buffer.write_position();

    // Seek to beginning and write header placeholder (0)
    buffer.write_seek(hexi::buffer_seek::set, 0);
    uint32_t placeholder = 0;
    buffer.write(reinterpret_cast<const std::byte*>(&placeholder), sizeof(placeholder));

    // Write body content (example body data)
    // Seek back to after header to write body
    buffer.write_seek(hexi::buffer_seek::set, sizeof(placeholder));

    // Example: write some body data
    std::vector<std::byte> body_data = {std::byte{0x01}, std::byte{0x02}, std::byte{0x03}};
    buffer.write(body_data.data(), body_data.size());

    // Seek back to beginning to update header with actual value
    buffer.write_seek(hexi::buffer_seek::set, 0);
    buffer.write(reinterpret_cast<const std::byte*>(&header_value), sizeof(header_value));

    // Restore original position or seek to end for continued writing
    buffer.write_seek(hexi::buffer_seek::set, current_pos + sizeof(header_value) + body_data.size() - sizeof(placeholder));
}

