ReadLimitInfo catch_stream_read_limit() {
    ReadLimitInfo info = {0, 0, 0, false};

    try {
        std::vector<std::byte> buffer(1000);
        hexi::pmc::buffer_adaptor adaptor(buffer);

        // Create stream with read limit of 10 bytes
        hexi::pmc::binary_stream stream(adaptor, 10);

        // Attempt to read more than the limit
        std::vector<std::byte> dest(100);
        stream.get(dest.data(), dest.size());
    } catch (const hexi::stream_read_limit& e) {
        info.read_size = e.read_size;
        info.total_read = e.total_read;
        info.read_limit = e.read_limit;
        info.occurred = true;
    }

    return info;
}

ReadLimitInfo safe_read_with_limit_check(hexi::pmc::binary_stream& stream, void* destination, std::size_t length) {
    ReadLimitInfo info = {0, 0, 0, false};

    try {
        // Use stream's get method to read data
        // get() requires a typed pointer, so cast void* to std::byte*
        // count is number of bytes, so we pass length as count for std::byte
        stream.get(static_cast<std::byte*>(destination), length);
    } catch (const hexi::stream_read_limit& e) {
        info.read_size = e.read_size;
        info.total_read = e.total_read;
        info.read_limit = e.read_limit;
        info.occurred = true;
    }

    return info;
}

